6156 bool llvm::canIgnoreSignBitOfZero(const Use &U) {
6157   auto *User = cast<Instruction>(U.getUser());
6158   if (auto *FPOp = dyn_cast<FPMathOperator>(User)) {
6159     if (FPOp->hasNoSignedZeros())
6160       return true;
6161   }
