6164   case Instruction::FPToSI:
6165   case Instruction::FPToUI:
6166     return true;
6167   case Instruction::FCmp:
6168     // fcmp treats both positive and negative zero as equal.
6169     return true;
6170   case Instruction::Call:
6171     if (auto *II = dyn_cast<IntrinsicInst>(User)) {
6172       switch (II->getIntrinsicID()) {
6173       case Intrinsic::fabs:
6174         return true;
6175       case Intrinsic::copysign:
6176         return U.getOperandNo() == 0;
6177       case Intrinsic::is_fpclass:
6178       case Intrinsic::vp_is_fpclass: {
6179         auto Test =
6180             static_cast<FPClassTest>(
6181                 cast<ConstantInt>(II->getArgOperand(1))->getZExtValue()) &
6182             FPClassTest::fcZero;
